import{_ as a,c as e,o as r,a1 as d}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"Платформы и интеграция: многоканальный доступ к протокола | Antigravity-Manager","description":"Изучите методы интеграции платформ протоколов в Antigravity Tools. Поддерживает унифицированную API-шлюз преобразование семи протоколов OpenAI, Anthropic, Gemini и др.","frontmatter":{"layout":"page","title":"Платформы и интеграция: многоканальный доступ к протокола | Antigravity-Manager","sidebarTitle":"Подключите вашу AI платформу","subtitle":"Платформы и интеграция: многоканальный доступ к протокола","description":"Изучите методы интеграции платформ протоколов в Antigravity Tools. Поддерживает унифицированную API-шлюз преобразование семи протоколов OpenAI, Anthropic, Gemini и др.","order":200},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/platforms/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/platforms/index.md"}'),i={name:"ru/lbjlaq/Antigravity-Manager/platforms/index.md"};function o(l,t,n,c,h,s){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="платформы-и-интеграция" tabindex="-1">Платформы и интеграция <a class="header-anchor" href="#платформы-и-интеграция" aria-label="Permalink to &quot;Платформы и интеграция&quot;">​</a></h1><p>Основная возможность Antigravity Tools — преобразовывать протоколы нескольких платформ AI в унифицированную локальную API-шлюз. В этой главе подробно описываются способы подключения, границы совместимости и лучшие практики каждого протокола.</p><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Урок</th><th>Описание</th></tr></thead><tbody><tr><td><a href="./openai/">OpenAI-совместимый API</a></td><td>Стратегия реализации <code>/v1/chat/completions</code> и <code>/v1/responses</code>, безболезненный доступ OpenAI SDK</td></tr><tr><td><a href="./anthropic/">Anthropic-совместимый API</a></td><td>Ключевой контракт <code>/v1/messages</code> с Claude Code, поддержка цепочки размышлений, системных подсказок и других основных возможностей</td></tr><tr><td>---</td><td>---</td></tr><tr><td><a href="./imagen/">Imagen 3 генерация изображений</a></td><td>Автоматическое отображение параметров <code>size</code>/<code>quality</code> OpenAI Images, поддержка произвольных соотношений сторон</td></tr><tr><td><a href="./audio/">Транскрибация аудио</a></td><td>Ограничения <code>/v1/audio/transcriptions</code> и обработка больших пакетов</td></tr><tr><td><a href="./mcp/">Конечные точки MCP</a></td><td>Предоставление Web Search/Reader/Vision в качестве вызываемых инструментов</td></tr><tr><td><a href="./cloudflared/">Туннель Cloudflared</a></td><td>Одним кликом безопасно открывать локальный API в публичную сеть (не является безопасным по умолчанию)</td></tr></tbody></table><h2 id="рекомендуемыи-путь-обучения" tabindex="-1">Рекомендуемый путь обучения <a class="header-anchor" href="#рекомендуемыи-путь-обучения" aria-label="Permalink to &quot;Рекомендуемый путь обучения&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Рекомендуемый порядок</p><p>Сначала изучайте протокол, который используете:</p></div><p><strong>Быстрый выбор</strong>:</p><table tabindex="0"><thead><tr><th>Ваш сценарий</th><th>Рекомендуется начать с</th></tr></thead><tbody><tr><td>Используете Claude Code CLI</td><td><a href="./anthropic/">Anthropic-совместимый API</a></td></tr><tr><td>Используете OpenAI Python SDK</td><td><a href="./openai/">OpenAI-совместимый API</a></td></tr><tr><td>Используете официальный Google SDK</td><td><a href="./gemini/">Gemini-нативный API</a></td></tr><tr><td>Нужен ИИ-рисование</td><td><a href="./imagen/">Imagen 3 генерация изображений</a></td></tr><tr><td>Нужна распознавание речи в текст</td><td><a href="./audio/">Транскрибация аудио</a></td></tr><tr><td>Нужен поиск в сети / чтение веб-страниц</td><td><a href="./mcp/">Конечные точки MCP</a></td></tr><tr><td>Нужен удаленный доступ</td><td><a href="./cloudflared/">Туннель Cloudflared</a></td></tr></tbody></table><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Перед началом убедитесь</p><ul><li>Установлена и обновлена <a href="./../start/installation/">установка</a></li><li>Выполнено <a href="./../start/add-account/">добавление учетной записи</a></li><li>Выполнен <a href="./../start/proxy-and-first-client/">запуск локального обратного прокси</a> (минимум доступ к <code>/healthz</code>)</li></ul></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После изучения этой главы вы можете продолжить обучение:</p><ul><li><a href="./../advanced/">Расширенная конфигурация</a>: маршрутизация моделей, управление квотой, высокодоступное планирование и другие расширенные функции</li><li><a href="./../faq/">Часто задаваемые вопросы</a>: руководство по устранению неполадок при ошибках 401/404/429</li></ul>',13)])])}const u=a(i,[["render",o]]);export{f as __pageData,u as default};
